import{_ as e,o as a,c as n,a2 as i}from"./chunks/framework.DfwzJIgY.js";const u=JSON.parse('{"title":"Project Structure","description":"","frontmatter":{},"headers":[],"relativePath":"guide/project-structure.md","filePath":"guide/project-structure.md"}'),t={name:"guide/project-structure.md"};function r(l,s,p,o,d,c){return a(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="project-structure" tabindex="-1">Project Structure <a class="header-anchor" href="#project-structure" aria-label="Permalink to &quot;Project Structure&quot;">​</a></h1><p>Orbital-Express uses a <strong>feature-folder architecture</strong> inspired by Django&#39;s app-based layout and Rails&#39; MVC conventions. Almost everything you build lives in <code>app/</code> — one folder per database table. Everything else at the repo root is the <strong>global layer</strong>: shared infrastructure, cross-feature utilities, and the three process entry points.</p><h2 id="full-tree" tabindex="-1">Full Tree <a class="header-anchor" href="#full-tree" aria-label="Permalink to &quot;Full Tree&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>repo root</span></span>
<span class="line"><span>├── app/                        # ALL features — one singular-PascalCase folder per table</span></span>
<span class="line"><span>│   ├── User/</span></span>
<span class="line"><span>│   │   ├── actions/            # one file per action (V1Login.js, V1Register.js, …)</span></span>
<span class="line"><span>│   │   │   └── index.js        # barrel export for all actions in this feature</span></span>
<span class="line"><span>│   │   ├── tests/</span></span>
<span class="line"><span>│   │   │   ├── integration/    # action integration tests</span></span>
<span class="line"><span>│   │   │   └── tasks/          # task unit tests</span></span>
<span class="line"><span>│   │   ├── languages/          # feature-scoped i18n source strings</span></span>
<span class="line"><span>│   │   ├── mailers/            # feature-scoped email templates (optional)</span></span>
<span class="line"><span>│   │   ├── controller.js       # gates auth/type, dispatches to actions</span></span>
<span class="line"><span>│   │   ├── error.js            # feature-scoped ERROR_CODES</span></span>
<span class="line"><span>│   │   ├── helper.js           # feature-scoped utilities (promote to global when shared)</span></span>
<span class="line"><span>│   │   ├── model.js            # Sequelize model definition</span></span>
<span class="line"><span>│   │   ├── routes.js           # Express router for this feature</span></span>
<span class="line"><span>│   │   └── worker.js           # task definitions (background jobs) for this feature</span></span>
<span class="line"><span>│   ├── Admin/                  # same structure as User</span></span>
<span class="line"><span>│   └── feature.js              # generator template (do not edit)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── index.js                    # web entry point — boots server.js via throng (clustered)</span></span>
<span class="line"><span>├── server.js                   # Express app: middleware stack, routes, socket, error handler</span></span>
<span class="line"><span>├── worker.js                   # worker entry point — registers all queue task processors</span></span>
<span class="line"><span>├── cronjobs.js                 # cron entry point — schedules jobs on the clock process</span></span>
<span class="line"><span>├── routes.js                   # GLOBAL route aggregator — mounts every feature&#39;s routes.js</span></span>
<span class="line"><span>├── models.js                   # GLOBAL model aggregator — scans app/*/model.js into one object</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── middleware/</span></span>
<span class="line"><span>│   ├── id.js                   # stamps every request with a unique requestId</span></span>
<span class="line"><span>│   ├── args.js                 # normalises req.body/req.query → req.args; parses filter operators</span></span>
<span class="line"><span>│   ├── auth.js                 # runs Passport JWT strategies; populates req.user / req.admin</span></span>
<span class="line"><span>│   ├── error.js                # catches thrown errors; formats and returns error responses</span></span>
<span class="line"><span>│   └── exit.js                 # graceful-shutdown middleware + gracefulExit() drain function</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── services/</span></span>
<span class="line"><span>│   ├── queue.js                # Bull queue manager (queue.get / queue.closeAll)</span></span>
<span class="line"><span>│   ├── redis.js                # Redis client singleton</span></span>
<span class="line"><span>│   ├── socket.js               # Socket.IO server + JWT verification</span></span>
<span class="line"><span>│   ├── email.js                # transactional email sending (nodemailer / SendGrid)</span></span>
<span class="line"><span>│   ├── language.js             # i18n lookup helper</span></span>
<span class="line"><span>│   ├── passport.js             # Passport JWT strategies (one per auth user type)</span></span>
<span class="line"><span>│   ├── postgres.js             # raw Postgres client (for queries outside Sequelize)</span></span>
<span class="line"><span>│   ├── secure.js               # AES-256-GCM encryption/decryption for sensitive fields</span></span>
<span class="line"><span>│   ├── error.js                # errorResponse(), ERROR_CODES, joiErrorsMessage</span></span>
<span class="line"><span>│   └── phone.js                # phone/SMS integration wrapper</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── helpers/</span></span>
<span class="line"><span>│   ├── constants.js            # global enums and status sets (UPPER_CASE, dual-export)</span></span>
<span class="line"><span>│   ├── cruqd.js                # Create/Read/Update/Query/Delete Sequelize helpers + filter parsing</span></span>
<span class="line"><span>│   ├── logic.js                # auth token helpers (createAccessToken, createRefreshToken, hashToken)</span></span>
<span class="line"><span>│   ├── schemas.js              # reusable Joi schema fragments</span></span>
<span class="line"><span>│   ├── session.js              # refresh-token session mechanics (issueSession, revokeSession)</span></span>
<span class="line"><span>│   ├── tests.js                # shared test utilities</span></span>
<span class="line"><span>│   └── validate.js             # Joi validation wrappers</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── database/</span></span>
<span class="line"><span>│   ├── schema.sql              # human-readable master schema (documentation only — never executed)</span></span>
<span class="line"><span>│   ├── sequence.js             # ordered array of all tables (generator-maintained — do not edit by hand)</span></span>
<span class="line"><span>│   ├── index.js                # Sequelize connection (used by the running app)</span></span>
<span class="line"><span>│   ├── seed/                   # dev seed data, loaded by \`yarn seed\`</span></span>
<span class="line"><span>│   │   └── set1/               # one folder per seed set; each subfolder is a table</span></span>
<span class="line"><span>│   └── backups/                # DB dumps from \`yarn backup\`; restored with \`yarn restore\`</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── migrations/                 # ordered Sequelize migration files (applied by \`yarn migrate\`)</span></span>
<span class="line"><span>├── models/                     # intentionally near-empty — models live in app/*/model.js</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── languages/                  # GLOBAL i18n source strings (en.js, …)</span></span>
<span class="line"><span>├── locales/                    # COMPILED i18n output from \`yarn lang\` — never edit by hand</span></span>
<span class="line"><span>├── mailers/                    # global email templates (feature mailers live in app/&lt;F&gt;/mailers/)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── config/</span></span>
<span class="line"><span>│   ├── .env.template           # committed reference — copy and fill in for each environment</span></span>
<span class="line"><span>│   ├── .env.development        # gitignored</span></span>
<span class="line"><span>│   ├── .env.test               # gitignored</span></span>
<span class="line"><span>│   ├── .env.staging            # gitignored (optional, for connecting to staging locally)</span></span>
<span class="line"><span>│   ├── .env.production         # gitignored (optional, for connecting to prod locally)</span></span>
<span class="line"><span>│   ├── config.js               # Sequelize-CLI DB config (reads .env.* by NODE_ENV)</span></span>
<span class="line"><span>│   └── heroku-sync.js          # syncs a local .env file to a Heroku app</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── knowledge/                  # product knowledge base — .txt files + knowledge.js upsert script</span></span>
<span class="line"><span>├── docs/                       # all deep documentation (conventions.txt, workflow.md, …)</span></span>
<span class="line"><span>├── scripts/                    # standalone one-off scripts (run by hand, not in request flow)</span></span>
<span class="line"><span>├── redis/                      # project-local Redis build (gitignored — local dev only)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── test/                       # global test harness</span></span>
<span class="line"><span>│   ├── app/                    # stitches together each feature&#39;s test files</span></span>
<span class="line"><span>│   ├── fixtures/               # test-DB baseline data (fix1/…) — the test analog of database/seed</span></span>
<span class="line"><span>│   ├── helpers/                # unit tests for global helpers (test/helpers/&lt;name&gt;.test.js)</span></span>
<span class="line"><span>│   └── services/               # unit tests for global services (test/services/&lt;name&gt;.test.js)</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── public/                     # static assets</span></span>
<span class="line"><span>├── views/                      # server-rendered views (e.g. email preview pages)</span></span>
<span class="line"><span>├── AGENTS.md                   # canonical agent guide (tool-agnostic)</span></span>
<span class="line"><span>└── CLAUDE.md                   # Claude Code specifics (imports AGENTS.md)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br><span class="line-number">54</span><br><span class="line-number">55</span><br><span class="line-number">56</span><br><span class="line-number">57</span><br><span class="line-number">58</span><br><span class="line-number">59</span><br><span class="line-number">60</span><br><span class="line-number">61</span><br><span class="line-number">62</span><br><span class="line-number">63</span><br><span class="line-number">64</span><br><span class="line-number">65</span><br><span class="line-number">66</span><br><span class="line-number">67</span><br><span class="line-number">68</span><br><span class="line-number">69</span><br><span class="line-number">70</span><br><span class="line-number">71</span><br><span class="line-number">72</span><br><span class="line-number">73</span><br><span class="line-number">74</span><br><span class="line-number">75</span><br><span class="line-number">76</span><br><span class="line-number">77</span><br><span class="line-number">78</span><br><span class="line-number">79</span><br><span class="line-number">80</span><br><span class="line-number">81</span><br><span class="line-number">82</span><br><span class="line-number">83</span><br><span class="line-number">84</span><br><span class="line-number">85</span><br><span class="line-number">86</span><br><span class="line-number">87</span><br><span class="line-number">88</span><br><span class="line-number">89</span><br><span class="line-number">90</span><br><span class="line-number">91</span><br><span class="line-number">92</span><br><span class="line-number">93</span><br></div></div><hr><h2 id="the-three-entry-points" tabindex="-1">The Three Entry Points <a class="header-anchor" href="#the-three-entry-points" aria-label="Permalink to &quot;The Three Entry Points&quot;">​</a></h2><p>Orbital-Express runs as <strong>three separate processes</strong>. Each has its own entry point and is started independently. You need all three running in development.</p><h3 id="index-js-—-web-server" tabindex="-1"><code>index.js</code> — Web Server <a class="header-anchor" href="#index-js-—-web-server" aria-label="Permalink to &quot;\`index.js\` — Web Server&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> s</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # shorthand</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # full form</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>The web entry point. It uses <a href="https://github.com/hunterloftis/throng" target="_blank" rel="noreferrer">throng</a> to fork one worker per CPU core, then boots <code>server.js</code> in each. Signal handlers are registered in each worker for graceful shutdown (<code>SIGTERM</code> / <code>SIGINT</code>).</p><p><strong><code>server.js</code></strong> is where the actual Express app is assembled:</p><ol><li>Third-party middleware (helmet, cors, body-parser, rate limiter, …)</li><li>Custom global middleware in order: <code>id</code> → <code>args</code> → <code>auth</code></li><li>The global route aggregator (<code>routes.js</code>)</li><li>The error handler (<code>middleware/error.js</code>) — must be last</li></ol><p>Every incoming HTTP request flows through this chain. The final handler in the chain is the action function inside a feature folder.</p><h3 id="worker-js-—-background-job-worker" tabindex="-1"><code>worker.js</code> — Background Job Worker <a class="header-anchor" href="#worker-js-—-background-job-worker" aria-label="Permalink to &quot;\`worker.js\` — Background Job Worker&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> w</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # shorthand</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worker</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # full form</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>The Bull worker process. It imports every feature&#39;s <code>worker.js</code> file (which registers task processor functions against named queues). When a background job is enqueued by an action, this process picks it up, runs it, and handles retries and failures.</p><p>Use background tasks when work is too slow or too risky for a synchronous API response: report generation, sending bulk emails, calling slow third-party APIs, post-processing uploads. The action enqueues the job and returns <code>202 Accepted</code> immediately; the worker does the actual work.</p><h3 id="cronjobs-js-—-cron-clock" tabindex="-1"><code>cronjobs.js</code> — Cron Clock <a class="header-anchor" href="#cronjobs-js-—-cron-clock" aria-label="Permalink to &quot;\`cronjobs.js\` — Cron Clock&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cron</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The clock process. It defines which tasks get enqueued on which schedule using cron expressions. <strong>Exactly one instance</strong> of this process should run in production — it is not clustered.</p><p>The common pattern: the cron job enqueues a background task (in <code>worker.js</code>) rather than doing the work itself. This separates scheduling from execution, keeps the clock process lightweight, and lets the work be retried independently.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Every day at 12:00 noon</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>  cronjobs.js  ──enqueues──▶  Worker queue  ──runs──▶  background task</span></span>
<span class="line"><span>  (clock proc)                                          (does the real work)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><hr><h2 id="routes-js-and-models-js-—-global-aggregators" tabindex="-1"><code>routes.js</code> and <code>models.js</code> — Global Aggregators <a class="header-anchor" href="#routes-js-and-models-js-—-global-aggregators" aria-label="Permalink to &quot;\`routes.js\` and \`models.js\` — Global Aggregators&quot;">​</a></h2><h3 id="routes-js-root" tabindex="-1"><code>routes.js</code> (root) <a class="header-anchor" href="#routes-js-root" aria-label="Permalink to &quot;\`routes.js\` (root)&quot;">​</a></h3><p>Every feature&#39;s <code>routes.js</code> defines its own Express <code>Router</code>. The root <code>routes.js</code> mounts them all onto the Express app. When you create a new feature, you register its router here once.</p><div class="language-javascript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// routes.js — register each feature&#39;s router</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> userRoutes</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> require</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;./app/User/routes&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> orderRoutes</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> require</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;./app/Order/routes&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">module</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">exports</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  app.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">use</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;/&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, userRoutes);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  app.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">use</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;/&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, orderRoutes);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="models-js-root" tabindex="-1"><code>models.js</code> (root) <a class="header-anchor" href="#models-js-root" aria-label="Permalink to &quot;\`models.js\` (root)&quot;">​</a></h3><p>Models live in <code>app/&lt;Feature&gt;/model.js</code>, not in <code>models/</code>. The root <code>models.js</code> scans all feature model files and assembles them into a single <code>models</code> object. The <code>models/</code> directory is intentionally nearly empty — it is not where models are defined.</p><div class="language-javascript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// anywhere in the codebase</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> models</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> require</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;./models&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">models.user.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">findOne</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ where: { id } });</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">models.order.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">findAll</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ where: { userId } });</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>The aggregator also sets up Sequelize associations (after all models are loaded) so cross-feature associations can reference any model without circular-require issues.</p><hr><h2 id="app-—-the-heart-of-the-codebase" tabindex="-1"><code>app/</code> — The Heart of the Codebase <a class="header-anchor" href="#app-—-the-heart-of-the-codebase" aria-label="Permalink to &quot;\`app/\` — The Heart of the Codebase&quot;">​</a></h2><p>Every database table maps to one <strong>feature folder</strong> under <code>app/</code>. The folder name is <strong>singular PascalCase</strong> (<code>User</code>, <code>Order</code>, <code>InvoiceItem</code>). This is where almost all day-to-day development happens.</p><h3 id="what-is-a-feature" tabindex="-1">What is a Feature? <a class="header-anchor" href="#what-is-a-feature" aria-label="Permalink to &quot;What is a Feature?&quot;">​</a></h3><p>A feature is everything built around one database table. When you add a <code>Bookings</code> table, you are building the <code>Booking</code> feature: the model, the routes, the controller, the actions (create, read, update, delete, query), the tests, the i18n strings, and the background tasks.</p><p><strong>Feature-folder layout:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app/User/</span></span>
<span class="line"><span>├── actions/</span></span>
<span class="line"><span>│   ├── V1Login.js</span></span>
<span class="line"><span>│   ├── V1Logout.js</span></span>
<span class="line"><span>│   ├── V1LogoutAll.js</span></span>
<span class="line"><span>│   ├── V1Refresh.js</span></span>
<span class="line"><span>│   ├── V1Register.js</span></span>
<span class="line"><span>│   ├── V1Update.js</span></span>
<span class="line"><span>│   └── index.js          # barrel export — generator maintains this</span></span>
<span class="line"><span>├── tests/</span></span>
<span class="line"><span>│   ├── integration/      # one test file per action</span></span>
<span class="line"><span>│   └── tasks/            # one test file per background task</span></span>
<span class="line"><span>├── languages/            # feature-scoped i18n source strings</span></span>
<span class="line"><span>├── mailers/              # feature-scoped email templates</span></span>
<span class="line"><span>├── controller.js         # auth gating + action dispatch</span></span>
<span class="line"><span>├── error.js              # feature-scoped ERROR_CODES</span></span>
<span class="line"><span>├── helper.js             # utilities private to this feature</span></span>
<span class="line"><span>├── model.js              # Sequelize model + associations</span></span>
<span class="line"><span>├── routes.js             # Express Router (POST/GET only)</span></span>
<span class="line"><span>└── worker.js             # Bull task processor definitions</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><p><strong>The request flow inside a feature:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>routes.js  →  controller.js  →  actions/V1Action.js  →  (response or enqueue task)</span></span>
<span class="line"><span>                                         │</span></span>
<span class="line"><span>                                    model / helpers / services</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>routes.js</code> maps URL paths to controller methods. The controller checks authentication and dispatches to the right action. The action validates <code>req.args</code> with Joi, runs business logic, calls the model, and returns a response.</p><p><strong>Always scaffold with the generator — never create feature files by hand:</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> User</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # scaffold the full feature folder</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> User</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> V1Search</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # add one action to an existing feature</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> User</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> V1SendEmailTask</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # add a background task</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> User</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Welcome</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # add a mailer</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> del</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> User</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> V1Example</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # remove a generated action (also removes it from index.js)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="middleware-—-global-request-pipeline" tabindex="-1"><code>middleware/</code> — Global Request Pipeline <a class="header-anchor" href="#middleware-—-global-request-pipeline" aria-label="Permalink to &quot;\`middleware/\` — Global Request Pipeline&quot;">​</a></h2><p>Every HTTP request passes through the global middleware stack in this order:</p><table tabindex="0"><thead><tr><th>File</th><th>What it does</th></tr></thead><tbody><tr><td><code>id.js</code></td><td>Stamps <code>req.id</code> with a unique UUID. Returned in error responses as <code>requestId</code> for log correlation.</td></tr><tr><td><code>args.js</code></td><td>Normalises <code>req.body</code> (POST) or <code>req.query</code> (GET) into <code>req.args</code>. Also runs <code>parseUrlQueryFilter</code> to convert bracket-notation operators (<code>date[gte]=…</code>) into Sequelize operators. You never touch <code>req.body</code> or <code>req.query</code> directly in actions.</td></tr><tr><td><code>auth.js</code></td><td>Runs the Passport JWT strategy matching the <code>Authorization</code> header scheme (<code>jwt-user</code>, <code>jwt-admin</code>). On success, populates <code>req.user</code> or <code>req.admin</code> and sets the locale. On public routes, calls <code>next()</code> without error — the controller enforces auth.</td></tr><tr><td><code>error.js</code></td><td>The final Express error handler. Catches anything thrown from an action or passed to <code>next(err)</code>, formats it with <code>errorResponse</code>, and returns the appropriate HTTP status. Never return a 500 manually — let it propagate here.</td></tr><tr><td><code>exit.js</code></td><td>Dual-purpose: the <code>exit.middleware</code> short-circuits new requests with <code>503</code> once a shutdown signal is received; <code>gracefulExit(server)</code> drains queues, sockets, and the DB connection pool before the process exits.</td></tr></tbody></table><hr><h2 id="services-—-third-party-wrappers-and-shared-infrastructure" tabindex="-1"><code>services/</code> — Third-Party Wrappers and Shared Infrastructure <a class="header-anchor" href="#services-—-third-party-wrappers-and-shared-infrastructure" aria-label="Permalink to &quot;\`services/\` — Third-Party Wrappers and Shared Infrastructure&quot;">​</a></h2><p>Services are <strong>stateful or substantial</strong> shared infrastructure. If something wraps an external system, manages connections, or is too complex to be a plain function, it lives here.</p><table tabindex="0"><thead><tr><th>File</th><th>What it provides</th></tr></thead><tbody><tr><td><code>queue.js</code></td><td>Bull queue manager. <code>queue.get(&#39;UserQueue&#39;)</code> returns a named queue instance. <code>queue.closeAll()</code> is called on graceful shutdown.</td></tr><tr><td><code>redis.js</code></td><td>Shared Redis client. Used internally by <code>queue.js</code> and <code>socket.js</code>; also used directly for caching or pub/sub.</td></tr><tr><td><code>socket.js</code></td><td>Socket.IO server. Verifies access tokens (including <code>tokenVersion</code>) on connection, the same way HTTP auth does. See <a href="/orbital-express/realtime/sockets.html">Real-Time / Socket.IO</a> for the full architecture.</td></tr><tr><td><code>email.js</code></td><td>Transactional email dispatch. Accepts a rendered template and sends via the configured provider.</td></tr><tr><td><code>language.js</code></td><td>i18n lookup — reads from compiled <code>locales/</code> files. Used by actions and mailers via <code>lang.t(key, locale)</code>.</td></tr><tr><td><code>passport.js</code></td><td>One Passport JWT strategy per auth user type. Each strategy verifies signature, <code>exp</code>, <code>iss</code>, <code>aud</code>, and <code>tokenVersion</code>. The <code>AUTH_TYPES</code> registry in <code>middleware/auth.js</code> drives which strategy matches which <code>Authorization</code> scheme.</td></tr><tr><td><code>postgres.js</code></td><td>Raw <code>pg</code> client for queries that need to bypass Sequelize (migrations helpers, one-off admin queries).</td></tr><tr><td><code>secure.js</code></td><td>AES-256-GCM authenticated encryption for reversibly-stored sensitive fields. Uses a distinct secret from the auth tokens.</td></tr><tr><td><code>error.js</code></td><td><code>errorResponse()</code>, the global <code>ERROR_CODES</code> map, and <code>joiErrorsMessage()</code> for Joi validation errors.</td></tr><tr><td><code>phone.js</code></td><td>SMS / phone number wrapper (Twilio or equivalent).</td></tr></tbody></table><p><strong>Rule of thumb:</strong> if the module is a small, pure, stateless function it belongs in <code>helpers/</code>. If it wraps an external system, holds a connection, or has meaningful setup state, it belongs in <code>services/</code>.</p><hr><h2 id="helpers-—-small-pure-utilities" tabindex="-1"><code>helpers/</code> — Small Pure Utilities <a class="header-anchor" href="#helpers-—-small-pure-utilities" aria-label="Permalink to &quot;\`helpers/\` — Small Pure Utilities&quot;">​</a></h2><p>Helpers are <strong>small, pure, stateless functions</strong> shared across features. No connections, no side effects.</p><table tabindex="0"><thead><tr><th>File</th><th>What it provides</th></tr></thead><tbody><tr><td><code>constants.js</code></td><td>All global enums and status sets (e.g. <code>LOCALE</code>, <code>TOKEN_AUDIENCE</code>, <code>PLATFORMS</code>). Uses the dual-export pattern so constants are accessible both as named exports and as a single object. <strong>No magic strings</strong> — any literal used in more than one place lives here.</td></tr><tr><td><code>cruqd.js</code></td><td>Sequelize CRUD + Query helpers. <code>parseUrlQueryFilter</code> converts bracket-notation URL filters into Sequelize <code>Op</code> operators.</td></tr><tr><td><code>logic.js</code></td><td>Auth token utilities: <code>createAccessToken</code>, <code>createRefreshToken</code>, <code>hashToken</code>, <code>parseDurationMs</code>, <code>resolveClient</code>.</td></tr><tr><td><code>schemas.js</code></td><td>Reusable Joi schema fragments (e.g. pagination params, UUID validators) shared across feature actions.</td></tr><tr><td><code>session.js</code></td><td>Refresh-token session mechanics: <code>issueSession</code> (creates a session row), <code>revokeSession</code>, rotation logic.</td></tr><tr><td><code>tests.js</code></td><td>Shared test utilities (request builders, auth header helpers, assertion shortcuts).</td></tr><tr><td><code>validate.js</code></td><td>Joi validation wrappers used by actions before business logic runs.</td></tr></tbody></table><p><strong>Promotion rule:</strong> if a helper starts in a feature&#39;s <code>helper.js</code> and you need it from a second feature, move it to <code>helpers/</code> and update both imports. Never duplicate shared logic across feature folders.</p><p><strong>Global helpers need tests.</strong> Any time you add or modify a global helper, write or update its unit test in <code>test/helpers/&lt;name&gt;.test.js</code>. These are pure unit tests — no server, no DB.</p><hr><h2 id="database-—-schema-seed-and-backups" tabindex="-1"><code>database/</code> — Schema, Seed, and Backups <a class="header-anchor" href="#database-—-schema-seed-and-backups" aria-label="Permalink to &quot;\`database/\` — Schema, Seed, and Backups&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>database/index.js</code></td><td>Sequelize connection used by the running app. Separate from <code>config/config.js</code> which is only for the Sequelize CLI.</td></tr><tr><td><code>database/schema.sql</code></td><td><strong>Documentation only</strong> — a human-readable record of every table and column. Never executed. Keep it updated whenever you change the DB; it is the fastest way for a new engineer to understand the full data model.</td></tr><tr><td><code>database/sequence.js</code></td><td>Ordered array of all table names. Controls the order seed data and fixtures are loaded (respects FK dependencies). <strong>Maintained automatically by the generator</strong> (<code>yarn gen</code> / <code>yarn del</code>) — do not edit by hand unless you have to manually override something.</td></tr><tr><td><code>database/seed/</code></td><td>Dev seed data, grouped into sets (<code>set1/</code>, <code>set2/</code>, …). Loaded with <code>yarn seed</code>. Keep the number of sets small — every new column means updating every set.</td></tr><tr><td><code>database/backups/</code></td><td>DB dumps created by <code>yarn backup</code>. Restored with <code>yarn restore</code> (drops and replaces the current DB).</td></tr></tbody></table><hr><h2 id="migrations-—-schema-changes" tabindex="-1"><code>migrations/</code> — Schema Changes <a class="header-anchor" href="#migrations-—-schema-changes" aria-label="Permalink to &quot;\`migrations/\` — Schema Changes&quot;">​</a></h2><p>Real, ordered Sequelize migration files. These are what actually alter the database in development and production. Create one with:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sequelize</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migration:create</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> descriptive-name</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Follow the <code>add-migration</code> skill for the full naming and content conventions. Migrations are frozen snapshots — never edit an already-applied migration; write a new one instead.</p><hr><h2 id="languages-and-locales-—-internationalisation" tabindex="-1"><code>languages/</code> and <code>locales/</code> — Internationalisation <a class="header-anchor" href="#languages-and-locales-—-internationalisation" aria-label="Permalink to &quot;\`languages/\` and \`locales/\` — Internationalisation&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>languages/       # source of truth — edit these</span></span>
<span class="line"><span>  en.js</span></span>
<span class="line"><span>  es.js</span></span>
<span class="line"><span>locales/         # compiled output — never edit by hand</span></span>
<span class="line"><span>  en.json</span></span>
<span class="line"><span>  es.json</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>Global i18n source strings live in <code>languages/</code>. Feature-specific strings live in <code>app/&lt;Feature&gt;/languages/</code>. After editing any source file, run:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lang</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # compiles languages/ → locales/ and validates all keys</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>yarn test</code> runs <code>yarn lang</code> first — if keys are missing or invalid, the suite fails before any tests run.</p><p>For the full i18n reference — key naming, locale detection order, tasks vs actions, adding a new locale, key safety mechanisms — see <strong><a href="./../i18n/localization.html">docs/i18n/localization.md</a></strong>.</p><hr><h2 id="config-—-environment-configuration" tabindex="-1"><code>config/</code> — Environment Configuration <a class="header-anchor" href="#config-—-environment-configuration" aria-label="Permalink to &quot;\`config/\` — Environment Configuration&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>config/</span></span>
<span class="line"><span>├── .env.template     # committed — reference for all variables</span></span>
<span class="line"><span>├── .env.development  # gitignored</span></span>
<span class="line"><span>├── .env.test         # gitignored</span></span>
<span class="line"><span>├── .env.staging      # gitignored</span></span>
<span class="line"><span>├── .env.production   # gitignored</span></span>
<span class="line"><span>├── config.js         # Sequelize CLI config (reads .env.* by NODE_ENV)</span></span>
<span class="line"><span>└── heroku-sync.js    # syncs a .env file to a Heroku app</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>Copy <code>.env.template</code> to create each environment file. The minimum required variables:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Purpose</th></tr></thead><tbody><tr><td><code>NODE_ENV</code></td><td><code>development</code> / <code>test</code> / <code>production</code> — selects which <code>.env.*</code> loads.</td></tr><tr><td><code>DATABASE_URL</code></td><td>Postgres connection string. Use a <strong>separate DB</strong> for <code>.env.test</code>.</td></tr><tr><td><code>REDIS_URL</code></td><td>Redis connection (Bull queues + Socket.IO adapter).</td></tr><tr><td><code>ACCESS_TOKEN_SECRET</code></td><td>JWT signing secret — must be <strong>distinct</strong> from the refresh secret.</td></tr><tr><td><code>REFRESH_TOKEN_SECRET</code></td><td>Refresh token signing secret — must differ from access secret.</td></tr><tr><td><code>ACCESS_TOKEN_EXPIRES_IN</code></td><td>Access token lifetime, e.g. <code>15m</code>.</td></tr><tr><td><code>REFRESH_TOKEN_EXPIRES_IN</code></td><td>Refresh token lifetime, e.g. <code>60d</code>.</td></tr></tbody></table><p>All four auth variables must appear in <strong>every</strong> env file including <code>.env.test</code>. Missing auth vars in the test env causes auth tests to fail in confusing ways.</p><p><code>config/config.js</code> is read exclusively by the Sequelize CLI (via <code>.sequelizerc</code>). The running app connects through <code>database/index.js</code>. Both ultimately read the same <code>DATABASE_URL</code> — two doors into the same database.</p><hr><h2 id="test-—-global-test-harness" tabindex="-1"><code>test/</code> — Global Test Harness <a class="header-anchor" href="#test-—-global-test-harness" aria-label="Permalink to &quot;\`test/\` — Global Test Harness&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>test/</span></span>
<span class="line"><span>├── app/          # stitches together each feature&#39;s test files</span></span>
<span class="line"><span>├── fixtures/     # test-DB baseline data (fix1/, fix2/, …)</span></span>
<span class="line"><span>├── helpers/      # unit tests for global helpers</span></span>
<span class="line"><span>└── services/     # unit tests for global services</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Feature test files live <strong>inside the feature folder</strong> (<code>app/&lt;Feature&gt;/tests/</code>), not at the root of <code>test/</code>. The <code>test/app/</code> directory stitches them together so Jest can discover them as a single suite.</p><p><code>test/fixtures/</code> is the test analog of <code>database/seed/</code> — baseline data loaded into the test DB before the suite runs. Fixtures are the starting state; tests mutate in-place rather than creating everything from scratch.</p><p>Run the full suite:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # runs: yarn lang → sql fix1 → jest --runInBand</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>PostgreSQL <strong>and</strong> Redis must be running. <code>--runInBand</code> is required because tests share a single test database and must not run in parallel.</p><hr><h2 id="scripts-—-one-off-utilities" tabindex="-1"><code>scripts/</code> — One-Off Utilities <a class="header-anchor" href="#scripts-—-one-off-utilities" aria-label="Permalink to &quot;\`scripts/\` — One-Off Utilities&quot;">​</a></h2><p>Standalone scripts you run by hand — not part of the request, worker, or cron flow. Examples: compile-lang utilities, password helpers, data-migration scripts, one-off admin tools. They read from the appropriate <code>.env.*</code> file and can connect to any environment&#39;s database directly.</p><hr><h2 id="why-feature-folder-architecture" tabindex="-1">Why Feature-Folder Architecture? <a class="header-anchor" href="#why-feature-folder-architecture" aria-label="Permalink to &quot;Why Feature-Folder Architecture?&quot;">​</a></h2><p>Feature-based organisation keeps all code related to one concern in one place. Compare:</p><p><strong>Feature-based (Orbital-Express):</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app/</span></span>
<span class="line"><span>  Order/</span></span>
<span class="line"><span>    model.js        ← all in one place</span></span>
<span class="line"><span>    routes.js</span></span>
<span class="line"><span>    controller.js</span></span>
<span class="line"><span>    actions/</span></span>
<span class="line"><span>    tests/</span></span>
<span class="line"><span>  Invoice/</span></span>
<span class="line"><span>    model.js</span></span>
<span class="line"><span>    routes.js</span></span>
<span class="line"><span>    …</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p><strong>Type-based (Rails-style):</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>models/</span></span>
<span class="line"><span>  order.js</span></span>
<span class="line"><span>  invoice.js</span></span>
<span class="line"><span>routes/</span></span>
<span class="line"><span>  order.js</span></span>
<span class="line"><span>  invoice.js</span></span>
<span class="line"><span>controllers/</span></span>
<span class="line"><span>  order.js</span></span>
<span class="line"><span>  invoice.js</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>As the codebase grows to dozens or hundreds of features, the Rails-style layout forces constant back-and-forth across the tree. The feature-based layout means a developer working on <code>Order</code> stays in <code>app/Order/</code> almost entirely. Fewer merge conflicts, faster navigation, and a cleaner mental model of what each folder owns.</p>`,99)])])}const b=e(t,[["render",r]]);export{u as __pageData,b as default};
